import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
// import Layout from "@components/layout";
// import BreadCrumb from "@components/common/breadcrumb";
import Seo from "@components/seo";
import { useLocation } from "@reach/router";
import CryptoTradingBotScreen from "@screens/crypto-trading-bot";
import Layout_v2 from "@components/layout_v2";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";

const CryptoTradingBot = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "Crypto Trading Bot", link: "" },
  ];
  const { data } = props;
  const location = useLocation();
  const fileUrl =
    data?.cryptoTradingBotImg?.childImageSharp?.gatsbyImageData?.images
      ?.fallback?.src;
  const validData = data?.allMetaJson?.nodes[0];

  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",

        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "AI-powered crypto trading bot development by Justtry Technologies enables automated trading, real-time market analysis, and advanced strategies to enhance trading decisions.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce)",
          addressLocality: "Madurai",
          addressCountry: "IN",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
        },
      },
      {
        "@type": "FAQPage",
        mainEntity: [
          {
            "@type": "Question",
            name: "Is it possible to make a crypto trading bot?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Yes, crypto trading bots can be built using algorithms and APIs to automate trades, analyze market data, and execute strategies based on predefined rules.",
            },
          },
          {
            "@type": "Question",
            name: "How much does it cost to develop a crypto trading bot?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Crypto trading bot development typically costs between $10,000 and $50,000+, depending on strategy complexity, integrations, and customization.",
            },
          },
          {
            "@type": "Question",
            name: "Do crypto trading bots actually make money?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Crypto trading bots can generate profits when configured with effective strategies and risk controls, but returns depend on market conditions and proper management.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <main>
        <CryptoTradingBotScreen db={db} />
      </main>
    </Layout_v2>
  );
};

export default CryptoTradingBot;

export const queryData = graphql`
  query MyQuery {
    cryptoTradingBotImg: file(
      relativePath: { eq: "crypto-trading-bot-development.png" }
    ) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(filter: { slug: { eq: "crypto-trading-bot-development" } }) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
